from dataclasses import dataclass, field
from datetime import datetime, timedelta
from enum import Enum

class DataCategory(str, Enum):
    CONVERSATION_CONTENT = "conversation_content"
    EMAIL_ADDRESS        = "email_address"
    PAYMENT_INFO         = "payment_info"
    API_KEYS             = "api_keys"
    IP_ADDRESS           = "ip_address"

@dataclass
class DataBreachAssessment:
    incident_id: str
    discovered_at: datetime
    data_categories: list[DataCategory]
    approximate_records_affected: int
    eu_residents_affected: bool
    high_risk_to_individuals: bool   # e.g. special category data, financial data

    def gdpr_dpa_deadline(self) -> datetime | None:
        if not self.eu_residents_affected:
            return None
        return self.discovered_at + timedelta(hours=72)

    def gdpr_individual_notification_required(self) -> bool:
        return self.eu_residents_affected and self.high_risk_to_individuals

    def hours_until_dpa_deadline(self, as_of: datetime | None = None) -> float | None:
        deadline = self.gdpr_dpa_deadline()
        if deadline is None:
            return None
        now = as_of or datetime.utcnow()
        return (deadline - now).total_seconds() / 3600

    def is_dpa_deadline_at_risk(self, as_of: datetime | None = None) -> bool:
        hours_left = self.hours_until_dpa_deadline(as_of)
        if hours_left is None:
            return False
        return hours_left < 24   # alert when < 24h remain

from dataclasses import dataclass
from datetime import datetime, date
from decimal import Decimal

@dataclass
class EnterpriseAccount:
    account_id: str
    name: str
    tier: str          # "standard", "enterprise", "enterprise_plus"
    sla_uptime_pct: Decimal
    monthly_fee_usd: Decimal
    tam_email: str     # Technical Account Manager

    def sla_downtime_budget_minutes_per_month(self) -> Decimal:
        days_in_month = Decimal("30")
        minutes_per_day = Decimal("1440")
        return days_in_month * minutes_per_day * (1 - self.sla_uptime_pct / 100)

@dataclass
class SLABreachNotification:
    incident_id: str
    account: EnterpriseAccount
    incident_start: datetime
    incident_end: datetime
    actual_downtime_minutes: float

    def sla_breached(self) -> bool:
        budget = float(self.account.sla_downtime_budget_minutes_per_month())
        return self.actual_downtime_minutes > budget

    def credit_amount_usd(self, credit_rate: Decimal = Decimal("0.10")) -> Decimal:
        if not self.sla_breached():
            return Decimal("0")
        return self.account.monthly_fee_usd * credit_rate

    def notification_due_by(self) -> datetime:
        # 48 hours from incident resolution per standard enterprise SLA
        return self.incident_end.replace(microsecond=0) + __import__("datetime").timedelta(hours=48)

    def draft_subject(self) -> str:
        return (
            f"Service Incident Report — {self.incident_id} — "
            f"{self.incident_start.strftime('%Y-%m-%d')}"
        )

from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum

class NotificationType(str, Enum):
    DPA_GDPR            = "dpa_gdpr"
    USER_INDIVIDUAL     = "user_individual"
    ENTERPRISE_CUSTOMER = "enterprise_customer"
    PUBLIC_REPORT       = "public_report"
    MEDIA_STATEMENT     = "media_statement"

@dataclass
class NotificationLogEntry:
    incident_id: str
    notification_type: NotificationType
    sent_at: datetime
    sent_by: str
    recipient: str              # DPA name, customer account ID, or "public"
    channel: str                # "email", "dpa_portal", "status_page", "blog"
    legal_approved_by: str | None
    content_hash: str           # SHA-256 of notification content for integrity

@dataclass
class IncidentNotificationLog:
    incident_id: str
    entries: list[NotificationLogEntry] = field(default_factory=list)

    def add(self, entry: NotificationLogEntry) -> None:
        if entry.incident_id != self.incident_id:
            raise ValueError("entry incident_id does not match log incident_id")
        self.entries.append(entry)

    def gdpr_compliance_status(self, discovered_at: datetime) -> dict:
        deadline = discovered_at + __import__("datetime").timedelta(hours=72)
        dpa_entries = [e for e in self.entries if e.notification_type == NotificationType.DPA_GDPR]
        if not dpa_entries:
            return {"compliant": False, "reason": "No DPA notification sent"}
        earliest = min(e.sent_at for e in dpa_entries)
        on_time = earliest <= deadline
        return {
            "compliant": on_time,
            "sent_at": earliest,
            "deadline": deadline,
            "hours_remaining_at_send": (deadline - earliest).total_seconds() / 3600,
        }
